#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=5e4+10;

struct Edge{
    int t;
    ll v;
};

int n,m;
ll dis[N],b[N];
vector<Edge> e[N];
bool vis[N];

void add(ll num){
    for(int i=59;i>=0;i--)
        if((num>>i)&1){
            if(b[i])
                num^=b[i];
            else{
                b[i]=num;
                break;
            }
        }
}

void dfs(int x){
    vis[x]=1;
    for(Edge y:e[x])
        if(vis[y.t])
            add(dis[x]^dis[y.t]^y.v);
        else{
            dis[y.t]=dis[x]^y.v;
            dfs(y.t);
        }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        ll w;
        scanf("%d%d%lld",&u,&v,&w);
        e[u].push_back({v,w});
        e[v].push_back({u,w});
    }
    dfs(1);
    ll ans=dis[n];
    for(int i=59;i>=0;i--)
        if(!((ans>>i)&1) && b[i])
            ans^=b[i];
    printf("%lld",ans);
    return 0;
}
